import{_ as a,o,c as n,a2 as t}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Epic: i18n","description":"","frontmatter":{},"headers":[],"relativePath":"epics/i18n.md","filePath":"epics/i18n.md"}'),i={name:"epics/i18n.md"};function s(l,e,c,d,r,u){return o(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="epic-i18n" tabindex="-1">Epic: i18n <a class="header-anchor" href="#epic-i18n" aria-label="Permalink to &quot;Epic: i18n&quot;">​</a></h1><blockquote><p>Internationalization infrastructure so the platform shell, Console, Account, and plugins can all serve users in their preferred language.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>📋 Planned</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Both phases are post-v1. Phase 1 wires the infrastructure end-to-end: manifest <code>i18n.supportedLocales</code> field, <code>next-intl</code> integration in the runtime, generate script message merging (plugin <code>messages/&lt;locale&gt;.json</code> → <code>runtime/generated/messages/&lt;locale&gt;.ts</code>), <code>sdk.i18n</code> surface, Console Languages section, and Account Language preference. Phase 2 ships four built-in translations (English, German, Sinhala, Tamil) for the runtime shell, Console, Account, and auth app — with Sinhala and Tamil validating the full stack beyond ASCII.</p><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0029-internationalization.html">RFC 0029 — Internationalization</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../plugin-development.html">plugin-development.md — i18n section (post-v1)</a></li><li><a href="./../self-hosting.html">self-hosting.md — Language config (post-v1)</a></li></ul><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="📋-11-1-—-internationalization-phase-1-—-infrastructure-rfc-0029" tabindex="-1">📋 11.1 — Internationalization, Phase 1 — Infrastructure (RFC 0029) <a class="header-anchor" href="#📋-11-1-—-internationalization-phase-1-—-infrastructure-rfc-0029" aria-label="Permalink to &quot;📋 11.1 — Internationalization, Phase 1 — Infrastructure (RFC 0029)&quot;">​</a></h4><p><strong>Goal:</strong> Wire the i18n infrastructure end-to-end: manifest field, platform config, transparent locale cookie, middleware injection, next-intl integration, generate script message merging, <code>sdk.i18n</code> surface, DB migration, Console Languages section, and Account Language preference.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/manifest</code>: optional <code>i18n.supportedLocales</code> field in schema; validation (English required; missing locale file → build fail); <code>manifestFieldNames</code> update for docs-parity test. Minor bump.</li><li><code>packages/db</code>: new nullable <code>locale TEXT</code> column on <code>account_prefs</code> + drizzle-kit migration for both dialects; <code>PlatformConfig</code> type gains <code>enabledLanguages</code>/<code>defaultLanguage</code>. Minor bump.</li><li><code>packages/sdk</code>: new experimental <code>sdk.i18n</code> module (<code>getLocale</code>, <code>getEnabledLanguages</code>, <code>getDefaultLanguage</code>); <code>SdkHost</code> <code>i18n</code> key; marked experimental in <code>docs/sdk-stability.md</code>. Minor bump.</li><li><code>scripts/generate-registry.ts</code>: <code>composeMessages()</code> step merges plugin <code>messages/&lt;locale&gt;.json</code> into <code>runtime/generated/messages/&lt;locale&gt;.ts</code> (namespaced by plugin ID + <code>platform</code> key for shell strings); generated files gitignored.</li><li><code>runtime</code>: new <code>GET /api/admin/i18n</code> route (admin-key-authed); <code>RESERVED_API_SEGMENTS</code> gains <code>&#39;i18n&#39;</code>; middleware locale resolution (<code>sv-locale</code> cookie → enabled_languages → default_language → <code>&#39;en&#39;</code>) + <code>x-sovereign-user-locale</code> header injection; <code>runtime/i18n/request.ts</code>; <code>next.config.ts</code> wrapped with <code>createNextIntlPlugin</code>; root layout <code>NextIntlClientProvider</code> + dynamic <code>lang={locale}</code> attribute. Minor bump.</li><li><code>plugins/console</code>: Languages section in Settings (enable/disable checkboxes, default language dropdown, plugin coverage table). Minor bump.</li><li><code>plugins/account</code>: Language preference in Preferences tab (dropdown of enabled languages; save writes <code>account_prefs.locale</code> + clears <code>sv-locale</code> cookie). Minor bump.</li><li><code>docs/plugin-development.md</code>: &quot;Internationalization&quot; section (manifest field, <code>messages/</code> convention, <code>sdk.i18n</code>, next-intl usage pattern).</li><li><code>docs/self-hosting.md</code>: &quot;Language config&quot; section (enabled languages, default language).</li><li>New dep: <code>next-intl</code> in <code>runtime/package.json</code>.</li></ul><p><strong>Dependencies:</strong> None (independent post-v1 task)</p><p><strong>SRS reference:</strong> RFC 0029</p><p><strong>Review checklist:</strong></p><ul><li><code>pnpm generate</code> emits <code>runtime/generated/messages/en.ts</code> with correct namespace structure</li><li>Plugin with no <code>i18n</code> field is unaffected; generates cleanly with zero i18n output</li><li>Middleware injects <code>x-sovereign-user-locale</code> on all requests; verify with <code>curl -H &quot;Cookie: sv-locale=de&quot;</code> and check response header</li><li>Console Settings shows Languages section; English pre-checked and disabled</li><li>Account Preferences shows Language dropdown; selecting a language persists and <code>sv-locale</code> cookie is set</li><li><code>pnpm format:check &amp;&amp; pnpm lint &amp;&amp; pnpm typecheck &amp;&amp; pnpm test</code> all pass</li><li>Docs-parity test passes: <code>i18n</code> manifest field and <code>sdk.i18n</code> surface documented</li></ul><hr><h4 id="📋-11-2-—-internationalization-phase-2-—-platform-shell-adoption-rfc-0029" tabindex="-1">📋 11.2 — Internationalization, Phase 2 — Platform shell adoption (RFC 0029) <a class="header-anchor" href="#📋-11-2-—-internationalization-phase-2-—-platform-shell-adoption-rfc-0029" aria-label="Permalink to &quot;📋 11.2 — Internationalization, Phase 2 — Platform shell adoption (RFC 0029)&quot;">​</a></h4><p><strong>Goal:</strong> Extract all platform chrome strings into <code>messages/en.json</code> files and ship four built-in translations — English (<code>en</code>), German (<code>de</code>), Sinhala (<code>si</code>), Tamil (<code>ta</code>) — for the runtime shell, Console, Account, and auth app. Sinhala and Tamil use non-Latin scripts, validating the full stack beyond ASCII.</p><p><strong>Deliverables:</strong></p><ul><li><code>runtime/messages/{en,de,si,ta}.json</code>: all platform chrome strings (sidebar nav, offline banner, error messages, health page labels, etc.)</li><li><code>plugins/console/messages/{en,de,si,ta}.json</code>: all Console UI strings; <code>manifest.json</code> gains <code>i18n: { supportedLocales: [&quot;en&quot;,&quot;de&quot;,&quot;si&quot;,&quot;ta&quot;] }</code></li><li><code>plugins/account/messages/{en,de,si,ta}.json</code>: all Account UI strings; same manifest update</li><li><code>apps/auth/messages/{en,de,si,ta}.json</code>: login, register, 2FA, password-reset strings; <code>apps/auth/i18n/request.ts</code>; <code>apps/auth/next.config.ts</code> wrapped with <code>createNextIntlPlugin</code>. Minor bump.</li><li>RFC 0017 plugin starter template (<code>packages/create-plugin</code>): scaffold includes <code>messages/en.json</code> stub + next-intl usage example.</li><li>E2E test: language switch to German (Latin) and Tamil (non-Latin) → Console/Account strings render in the selected language.</li></ul><p><strong>Dependencies:</strong> Task 1.0.3</p><p><strong>SRS reference:</strong> RFC 0029</p><p><strong>Review checklist:</strong></p><ul><li>User selects Tamil (<code>ta</code>) in Account → Console and Account strings render in Tamil script</li><li>User selects German (<code>de</code>) → Latin-script translation renders correctly</li><li>Plugin without <code>i18n</code> field (e.g. Launcher) renders English unchanged</li><li>Auth login page renders in correct locale</li><li><code>pnpm generate</code> runs without error with all four locale message files present</li><li><code>pnpm format:check &amp;&amp; pnpm lint &amp;&amp; pnpm typecheck &amp;&amp; pnpm test</code> all pass</li></ul><hr>',29)])])}const m=a(i,[["render",s]]);export{g as __pageData,m as default};
